set-variable.value:
#[%dw 2.0
output application/java

---
"<!DOCTYPE html>
<html>
<head>
<meta charset='UTF-8'>

<style>
body {
    margin: 0;
    padding: 0;
    background: #edf2f7;
    font-family: 'Segoe UI', Arial, sans-serif;
}

.wrapper {
    width: 100%;
    padding: 30px 0;
}

.container {
    max-width: 760px;
    margin: auto;
    background: white;
    border-radius: 18px;
    overflow: hidden;
    box-shadow: 0 10px 40px rgba(0, 0, 0, .12);
}

.header {
    background: linear-gradient(135deg, #003366, #0056b3, #007bff);
    padding: 35px;
    color: white;
}

.bank {
    font-size: 34px;
    font-weight: bold;
}

.tag {
    margin-top: 5px;
    font-size: 15px;
    opacity: .9;
}

.hero {
    padding: 35px;
    background: #f8fbff;
}

.hero h2 {
    margin: 0;
    color: #003366;
}

.hero p {
    line-height: 28px;
    color: #666;
}

.card {
    margin: 30px;
    border-radius: 15px;
    overflow: hidden;
    border: 1px solid #dde5ee;
}

.card-title {
    background: #003366;
    padding: 18px;
    color: white;
    font-size: 18px;
    font-weight: bold;
}

table {
    width: 100%;
    border-collapse: collapse;
}

td {
    padding: 16px;
    border-bottom: 1px solid #ececec;
    font-size: 15px;
}

td:first-child {
    font-weight: bold;
    background: #fafafa;
    width: 40%;
}

.balance {
    font-size: 28px;
    font-weight: bold;
    color: #009933;
}

.status {
    background: #d9f7e8;
    color: #0b8a3b;
    padding: 6px 14px;
    border-radius: 30px;
    display: inline-block;
    font-weight: bold;
}

.info {
    display: flex;
    gap: 18px;
    padding: 0 25px 25px;
}

.box {
    flex: 1;
    background: #f7fbff;
    padding: 22px;
    border-radius: 15px;
    text-align: center;
    border: 1px solid #d7e8ff;
}

.box h3 {
    margin: 10px 0;
    color: #003366;
}

.box p {
    font-size: 13px;
    color: #666;
    line-height: 22px;
}

.security {
    margin: 25px;
    padding: 20px;
    background: #fff8ea;
    border-left: 5px solid orange;
    border-radius: 10px;
}

.security h3 {
    margin-top: 0;
    color: #c67d00;
}

.footer {
    background: #003366;
    color: white;
    text-align: center;
    padding: 35px;
    font-size: 13px;
    line-height: 24px;
}

.footer a {
    color: #fff;
    text-decoration: none;
}
</style>

</head>

<body>

<div class='wrapper'>

<div class='container'>

<div class='header'>

<div class='bank'>
🏦 " ++ (payload.BANKNAME[0] default "N/A") ++ "
</div>

<div class='tag'>
Secure • Trusted • Digital Banking
</div>

</div>

<div class='hero'>

<h2>
Welcome,
<b>" ++ (upper(vars.inputpayload.FULLNAME[0]) default "N/A") ++ "</b> 👋
</h2>

<p>
Congratulations!
Please find your account details below.
Thank you for choosing <b>Real Bank</b> as your trusted financial partner.
</p>

</div>

<div class='card'>

<div class='card-title'>
💳 Account Details
</div>

<table>

<tr>
<td>Account Holder</td>
<td>" ++ (payload.FULLNAME[0] default "N/A") ++ "</td>
</tr>

<tr>
<td>Bank Name</td>
<td>" ++ (vars.bankname default "N/A") ++ "</td>
</tr>

<tr>
<td>Account Number</td>
<td><b>" ++ (vars.inputpayload.ACCOUNTNUMBER[0] default "N/A") ++ "</b></td>
</tr>

<tr>
<td>Date of Birth</td>
<td>" ++ (vars.inputpayload.DATEOFBIRTH[0] default "N/A") ++ "</td>
</tr>

<tr>
<td>Mobile Number</td>
<td>" ++ (vars.inputpayload.MOBILENUMBER[0] default "N/A") ++ "</td>
</tr>

<tr>
<td>Email Address</td>
<td>" ++ (vars.email default "customer@email.com") ++ "</td>
</tr>

<tr>
<td>Aadhaar</td>
<td>XXXX XXXX " ++ ((vars.inputpayload.ADHARNUMBER[0] as String default "N/A")[-4 to -1]) ++ "</td>
</tr>

<tr>
<td>Address</td>
<td>" ++ (vars.inputpayload.ADDRESS[0] default "N/A") ++ "</td>
</tr>

<tr>
<td>Status</td>
<td><span class='status'>" ++ (vars.status default "N/A") ++ "</span></td>
</tr>

<tr>
<td>Available Balance</td>
<td class='balance'>₹ " ++ (vars.inputpayload.BALANCE[0] default "0.00") ++ "</td>
</tr>

</table>

</div>

<div class='security'>

<h3>
🔒 Banking Security
</h3>

<ul>
<li>Never share your ATM PIN.</li>
<li>Never share OTP with anyone.</li>
<li>Real Bank never asks for passwords.</li>
<li>Enable SMS & Email transaction alerts.</li>
<li>Report fraudulent transactions immediately.</li>
</ul>

</div>

<div class='info'>

<div class='box'>
📱
<h3>Mobile Banking</h3>
<p>
Transfer money instantly.
Manage debit cards.
Recharge & bill payments.
</p>
</div>

<div class='box'>
🌐
<h3>Internet Banking</h3>
<p>
View statements.
Download reports.
Manage beneficiaries.
</p>
</div>

<div class='box'>
☎️
<h3>24×7 Support</h3>
<p>
Phone: +91 9494207062
<br><br>
Email: narsingbeesetti22@gmail.com
</p>
</div>

</div>

<div class='footer'>
<b>Thank you for banking with Real Bank.</b>
<br><br>
© 2026 Real Bank
<br>
This is an automated email. Please do not reply.
</div>

</div>

</div>

</body>

</html>"]
